import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import '../../estilos/autenticacion.css';

const CLAVE_USUARIO = 'cdl_usuario';

export default function PaginaLogin() {
  const navigate = useNavigate();
  const [correo, setCorreo] = useState('');
  const [password, setPassword] = useState('');
  const [mostrarPass, setMostrarPass] = useState(false);
  const [error, setError] = useState('');
  const [correoError, setCorreoError] = useState(false);
  const [passError, setPassError] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!correo || !password) return;
    let usuarioGuardado = null;
    try { const raw = localStorage.getItem(CLAVE_USUARIO); if (raw) usuarioGuardado = JSON.parse(raw); } catch {}
    if (usuarioGuardado && usuarioGuardado.email === correo && usuarioGuardado.password === password) {
      localStorage.setItem('cdl_sesion_activa', 'true');
      navigate('/');
    } else {
      setCorreoError(true); setPassError(true);
      setError('Correo o contraseña incorrectos.');
      setTimeout(() => { setCorreoError(false); setPassError(false); setError(''); }, 3000);
    }
  };

  return (
    <div className="pagina-autenticacion">
      <form id="formulario-inicio-sesion" onSubmit={handleSubmit}>
        <h1 className="titulo-formulario">LOGIN</h1>
        <nav className="barra-navegacion-pestanas">
          <Link to="/registro" className="pestana-navegacion pestana-navegacion--registro">Registrarse</Link>
          <Link to="/login" className="pestana-navegacion pestana-navegacion--inicio-sesion"><ins>Iniciar Sesión</ins></Link>
        </nav>
        <div className="campo-formulario">
          <label htmlFor="campo-correo">Correo</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type="email" id="campo-correo" placeholder="ejemplo@gmail.com" required value={correo}
              onChange={e => { setCorreo(e.target.value); setCorreoError(false); }}
              style={correoError ? { borderColor: '#ff0844' } : {}} />
            <span className="campo-formulario__icono">✉</span>
          </div>
        </div>
        <div className="campo-formulario">
          <label htmlFor="campo-contrasena">Contraseña</label>
          <div className="campo-formulario__contenedor-con-icono">
            <input type={mostrarPass ? 'text' : 'password'} id="campo-contrasena" placeholder="Introduce la contraseña" required value={password}
              onChange={e => { setPassword(e.target.value); setPassError(false); }}
              style={passError ? { borderColor: '#ff0844' } : {}} />
            <span className="campo-formulario__icono">👁</span>
          </div>
        </div>
        <div className="opcion-mostrar-contrasena">
          <input type="checkbox" id="activar-visibilidad-contrasena" checked={mostrarPass} onChange={e => setMostrarPass(e.target.checked)} />
          <label htmlFor="activar-visibilidad-contrasena">Mostrar Contraseña</label>
        </div>
        {error && <div style={{ fontFamily:'Rajdhani,sans-serif', fontSize:'0.78rem', fontWeight:600, letterSpacing:'1px', color:'#ff0844', textAlign:'center', padding:'6px 0' }}>{error}</div>}
        <button type="submit" id="boton-iniciar-sesion">Iniciar Sesión</button>
      </form>
    </div>
  );
}
